head.script:
// N_op_304_01_65b.jsp -> tn_304_01_12b

// 테스트 계정 pjk1030, 1111

// '▶ 조회조건
//     점소 : [4BB]의왕지점
//     작업계획일 : NULL
//     차량번호 : NULL
//     출도착등록여부 : 전체
//     컨테이너번호 : NULL
//     오더번호 : BC41904250096
// BC41012070084

// ▶ 기타 내용
//     쿼리 내 일자 조회 조건이 BETWEEN COL1 AND COL2 로 되어있으나, CO1 에 대한 값만 
//     입력받고 있어 일자를 넣으면 조회가 되지않음.
//     또한 차량번호에도 일자가 필요하며, 컨테이너번호로 조회 시에는 최신 데이터가 없는 듯 하다. 
//     따라서 오더번호로만 조회 가능


// String sUserId = loginDTO.getUserId();
// String sUserClsCd = loginDTO.getUserClsCd() == null ? "" : loginDTO.getUserClsCd();   
// String sClntNo = loginDTO.getClntNo() == null ? "" : loginDTO.getClntNo();  
// String sClntNm = loginDTO.getClntNm() == null ? "" : loginDTO.getClntNm();

scwin.memJson = $c.data.getMemInfo();
scwin.sUserId = scwin.memJson.userId
scwin.sUserClsCd = scwin.memJson.userClsCd
scwin.sClntNo = scwin.memJson.clntNo
scwin.sClntNm = scwin.memJson.clntNm
scwin.strFromDate = WebSquare.date.getCurrentServerDate() // 20251201


scwin.sLobranCd = scwin.memJson.lobranCd
scwin.oldche = "";
scwin.g_chkScroll = false;
scwin.pos_groupCode = 0;

scwin.onpageload = function () { };


// UDC에 값 세팅 방법
// UDC값 초기화(scwin.onpageload 이후 세팅됨)
scwin.onUdcCompleted = function () {
    console.log("----------- onUdcCompleted");

    // const codeOptions = [
    //     { grpCd: "SD070", compID: "co_lc_logisticsBranch" }    //과세구분
    // ];
    // $c.data.setCommonCode(codeOptions);

    wrkDt.setValue(scwin.strFromDate)

    // 테스트 데이터
    // ed_odrNo.setValue("BC41012070084");
    // wrkDt.setValue("");
    // ed_odrNo.setValue("BC41904250096");

    wrkDt.focus();
    sbm_joblevel.action = "/ncall.ds.co.RetreiveLoBranCMD.do"; // ds_joblevel.DataID = "/ds.co.RetreiveLoBranCMD.do";

    scwin.submitExcute(sbm_joblevel);
};


scwin.f_Retrieve = async function (e) {

    scwin.g_chkScroll = false; // 처음부터 RowPositionChanged event를 태우지 않는다.

    var che = "";
    che = "1";

    if (ed_vehclNoCd.getValue() == ""
        && ed_odrNo.getValue() == ""
        && ed_cntrNo.getValue() == ""
        && co_lc_transRsltsExistYn.getValue() == "") {
        $c.win.alert("차량번호 또는 오더번호 또는 컨테이너번호 또는 출도착등록여부 중에 하나 이상의 조회조건을 선택하십시오.");
        return;
    }

    if (wrkDt.getValue() == ""
        && ed_vehclNoCd.getValue() != ""
        && ed_odrNo.getValue() == ""
        && ed_cntrNo.getValue() == "") {
        $c.gus.cfAlertMsg("차량번호로 조회할 경우에는 작업계획일자를 입력해야합니다");
        return;
    }

    if (wrkDt.getValue() == ""
        && co_lc_transRsltsExistYn.getValue() != ""
        && ed_vehclNoCd.getValue() == ""
        && ed_odrNo.getValue() == ""
        && ed_cntrNo.getValue() == "") {
        $c.gus.cfAlertMsg("출도착등록여부로 조회할 경우에는 작업계획일자를 입력해야합니다");
        return;
    }

    dma_retrieve.set("vehclNo", txt_vehclNoNm.getValue()) // vehclNo -> txt_vehclNoNm
    dma_retrieve.set("wrkDt", wrkDt.getValue())
    dma_retrieve.set("odrNo", ed_odrNo.getValue())
    dma_retrieve.set("transWrkIndictNo", ipt_transWrkIndictNo.getValue())
    dma_retrieve.set("cntrNo", ed_cntrNo.getValue())
    dma_retrieve.set("cheAll", che)
    dma_retrieve.set("transRsltsExistYn", co_lc_transRsltsExistYn.getValue())
    dma_retrieve.set("wrkLobranCd", co_lc_logisticsBranch.getValue())

    await scwin.submitExcute(sbm_retrieve);

    scwin.oldche = "";
    var userId = scwin.sUserId;

    if (userId == "jiko") {
        let ret = await $c.win.confirm("배치를 돌리겠습니까?")
        if (ret == true) {
            // tr_batch.Action = "/tn.di.systemautomgnt.systemautomgnt.ExecuteCntrPdaWorkResultsCMD.do";
            sbm_batch.action = "/tn.di.systemautomgnt.systemautomgnt.ExecuteCntrPdaWorkResultsCMD.do";
            await scwin.submitExcute(sbm_batch);
        }
    }
};


scwin.f_Save = async function (e) {

    await scwin.f_cntrSeqSearch();

    var che = "";
    var v_isTransSaved = false;	//도어운송단계가 저장되었는지를 체크
    var v_lastRow = 0;

    if (!ds_emp2.getModifiedIndex().length) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["Data"]);
        return;
    }

    let validVal = await $c.gus.cfValidate([gr_emp2])

    if (!validVal) {
        return;
    }

    for (var i = ds_emp2.getTotalRow(); i >= 0; i--) {
        // modifyRowStatus
        if (ds_emp2.getRowStatusValue(i) == 3) {
            v_lastRow = i;
            break;
        }
    }

    // 출발일시 from ~ to 체크
    for (var i = 0; i < ds_emp2.getTotalRow(); i++) {

        let rowData = ds_emp2.getRowJSON(i);
        let rowLast = ds_emp2.getRowJSON(v_lastRow);

        if (i < v_lastRow) {
            if (((rowData["dptIoMgntYn"] == 0 && rowData["dptHh"] == "")
                || (rowData["arvIoMgntYn"] == 0 && rowData["arvHh"] == ""))
                && (rowLast["dptHh"] != "" || rowLast["arvHh"] != "")) {
                if (rowLast["realCmpstcrgYn"] == "1") {
                    //직도어 복화인 경우 이전단계 실적 체크 생략
                } else {
                    $c.gus.cfAlertMsg("이전단계의 실적이 발생하지 않은 상태에서 이후단계의 실적이 발생하면 안됩니다");
                    return;
                }
            }
        }

        switch (rowData["wrkStpCd"]) {
            case DsConstants.WRK_STP_CD_TRANS:
                if (rowData["arvIoMgntYn"] == 0 && rowData["arvHh"] != "") {
                    v_isTransSaved = true;
                } else if (rowData["arvIoMgntYn"] == 1 && rowData["dptHh"] != "") {
                    v_isTransSaved = true;
                }
                break;
            case DsConstants.WRK_STP_CD_RETRV:
                if (rowData["preWrkEndHh"] != "" || ds_emp2.getTotalRow() == 0) {
                    v_isTransSaved = true;
                }
                break;

            default:
                break;
        }

        if (ds_emp2.getRowStatusValue(i) == "3") {
            //경기지사인경우 샤시번호 필수입력..
            if (co_lc_logisticsBranch.getValue() == "4BB"
                && !$c.gus.cfIsNull(rowData["cntrNo"])
                && (!$c.gus.cfIsNull(rowData["dptHh"])
                    || !$c.gus.cfIsNull(rowData["arvHh"]))
                && $c.gus.cfIsNull(rowData["chassisNo"])) {
                $c.gus.cfAlertMsg(i + "번째 행의 샤시번호를 입력해야 합니다.");
                return;
            }

            if (rowData["cntrNo"] == "" && (rowData["dptHh"] != "" || rowData["arvHh"] != "")) {
                $c.gus.cfAlertMsg(i + "번째 행에서 컨테이너번호가 없는 상태에서 출도착일시가 입력되었습니다");
                return;
            }

            var stDtm = rowData["dptDt"] + rowData["dptHh"]; //== "" ?  "0000" : ds_emp2.NameValue(i, "dptHh")); 
            var endDtm = rowData["arvDt"] + rowData["arvHh"]; // 
            var dptDt = rowData["dptDt"]
            var dptHh = rowData["dptHh"]
            var arvDt = rowData["arvDt"]
            var arvHh = rowData["arvHh"]

            if (rowData["wrkStpCd"] != DsConstants.WRK_STP_CD_SHUTTLE
                && dptDt != "" && dptHh != "" && arvDt != "" && arvHh != "") {
                if (!scwin.f_DifferBetweenDate(stDtm, endDtm)) {
                    $c.gus.cfAlertMsg(i + "번째 데이타에서 시작일자가 종료일자 이전이어야 합니다.");
                    return;
                }
            }
        }
    }

    for (var i = 0; i < ds_emp2.getTotalRow(); i++) {
        let rowData = ds_emp2.getRowJSON(i);
        if (rowData["socYn"] == "1" && rowData["odrKndCd"] != DsConstants.ODR_KND_CD_OFF_HIRE_ODR) {
            $c.gus.cfAlertMsg("\n반출불가\n반출제어 대상 컨테이너 입니다.\nLINE 담당자에게 확인바랍니다." + "\n");
            return false;
        }
    }

    //원본값을 세팅
    for (i = 0; i < ds_emp2.getTotalRow(); i++) {
        if (ds_emp2.getRowStatusValue(i) == 3) {
            let rowData = ds_emp2.getRowJSON(i);
            ds_emp2.setCellData(i, "orgCntrNo", rowData["cntrNo"]);
            ds_emp2.setCellData(i, "orgCntrSizCd", rowData["cntrSizCd"]);
            ds_emp2.setCellData(i, "orgCntrTypCd", rowData["cntrTypCd"]);
            ds_emp2.setCellData(i, "orgSealNo", rowData["sealNo"]);
            ds_emp2.setCellData(i, "orgDptDt", rowData["dptDt"]);
            ds_emp2.setCellData(i, "orgDptHh", rowData["dptHh"]);
            ds_emp2.setCellData(i, "orgArvDt", rowData["arvDt"]);
            ds_emp2.setCellData(i, "orgArvHh", rowData["arvHh"]);
            ds_emp2.setCellData(i, "orgChassisNo", rowData["chassisNo"]);
        }
    }

    let retDate = await scwin.f_RowDifferBetweenDate();
    if (retDate) {
        return;
    }

    // -------------------------------------------------------------			    
    for (var i = 0; i < ds_emp2.getTotalRow(); i++) {
        for (var j = i + 1; j < ds_emp2.getTotalRow() + 1; j++) {

            let rowDataI = ds_emp2.getRowJSON(i);
            let rowDataJ = ds_emp2.getRowJSON(j);

            if (rowDataJ["cntrNo"] != "" && rowDataI["cntrNo"] != "") {
                if (rowDataI["wrkPathSeq"] == rowDataJ["wrkPathSeq"] &&
                    rowDataI["odrNo"] == rowDataJ["odrNo"] &&
                    rowDataJ["cntrNo"] != rowDataI["cntrNo"]) {
                    //ds_emp2.NameValue(j,"cntrNo")=ds_emp2.NameValue(i,"cntrNo");
                    $c.win.alert(j + "번째 줄에 같은 작업경로에 다른 컨테이너번호가 있습니다.");
                    ds_emp2.setCellData(j, "cntrNo", "");
                    return;
                }
                if (rowDataI["wrkPathSeq"] != rowDataJ["wrkPathSeq"] &&
                    rowDataI["odrNo"] == rowDataJ["odrNo"] &&
                    rowDataJ["cntrNo"] == rowDataI["cntrNo"]) {
                    $c.win.alert(j + "번째 줄에 다른 작업경로에   같은  컨테이너번호가 있습니다.");
                    ds_emp2.setCellData(j, "cntrNo", "");
                    return;
                }

                // 복화종류=컴바인 같은 작업경로순번인데 같은 컨테이너번호일 경우.
                if (rowDataI["wrkPathSeq"] != rowDataJ["wrkPathSeq"] &&
                    rowDataI["cmpstcrgKndCd"] == "CB" &&
                    rowDataJ["cmpstcrgKndCd"] == "CB" &&
                    rowDataJ["cntrNo"] == rowDataI["cntrNo"]) {
                    $c.win.alert(j + "번째 줄의 작업지시는 컴바인이므로 컨테이너번호가 달라야 합니다.");
                    ds_emp2.setCellData(j, "cntrNo", "");
                    ds_emp2.setCellData(j, "dptHh", rowDataI["dptHh"]);
                    ds_emp2.setCellData(j, "arvHh", rowDataI["arvHh"]);
                    return;
                }
            }
        }

        if (ds_emp2.getCellData(i, "cntrNo") != "") {

            let chkVal = await dscommon.cf_CheckCntrNo(ds_emp2.getCellData(i, "cntrNo"))
            if (!chkVal) {
                let confirmVal = $c.win.confirm(i + "번째 컨테이너 번호는 유효하지 않기 때문에 저장하지  못합니다. 계속진행하시겠습니까?")
                if (confirmVal == false) {
                    return;
                }
            }
        }
    }
    // -------------------------------------------------------------	
    let retHourCheck = await scwin.hourCheck()

    if (retHourCheck) {

        let retNullCheck = await scwin.hourNullCheck()

        if (retNullCheck) {
            // let msgVal = await $c.gus.cfConfirmMsg(MSG_CM_CRM_001)
            let msgVal = await $c.win.confirm(MSG_CM_CRM_001);
            if (msgVal == true) {
                // if (ds_retrieve.getTotalRow() == 0) {
                //     var GAUCE_DATASET_HEADER = "vehclNo:STRING(12)" +
                //         ",wrkDt:STRING(10)" +
                //         ",odrNo:STRING(13)" +
                //         ",transWrkIndictNo:STRING(10)" +
                //         ",cntrNo:STRING(11)" +
                //         ",cheAll:STRING(1)";

                //     ds_retrieve.SetDataHeader(GAUCE_DATASET_HEADER);
                // }

                dma_retrieve.set("vehclNo", txt_vehclNoNm.getValue()); // vehclNo -> txt_vehclNoNm
                dma_retrieve.set("wrkDt", wrkDt.getValue());
                dma_retrieve.set("odrNo", ed_odrNo.getValue());
                dma_retrieve.set("transWrkIndictNo", ipt_transWrkIndictNo.getValue()); // ???
                dma_retrieve.set("cntrNo", ed_cntrNo.getValue());
                dma_retrieve.set("cheAll", "1");
                scwin.pos_groupCode = ds_emp.getRowPosition();  // 저장 전의 위치 저장

                await scwin.submitExcute(sbm_saveEmp);
            }
        }
    }
};


//-------------------------------------------------------------------------
// Row 간 일자 체크 함수
//-------------------------------------------------------------------------
scwin.f_RowDifferBetweenDate = async function () {

    var total_cnt = ds_emp2.getTotalRow();
    var oldArvDt = "";
    var oldArvHh = "";
    var oldWrkStpCd = "";
    // var j = 0;

    for (var i = 0; i < total_cnt; i++) {
        // j = i - 1;

        let rowData = ds_emp2.getRowJSON(i);
        if (i == 1) {
            if (rowData["arvIoMgntYn"] == 0) {
                oldArvDt = rowData["arvDt"];
                oldArvHh = rowData["arvHh"];
            } else if (rowData["dptIoMgntYn"] == 0) {
                oldArvDt = rowData["dptDt"];
                oldArvHh = rowData["dptHh"];
            } else {
                oldArvDt = "";
                oldArvHh = "";
            }

            oldWrkStpCd = rowData["wrkStpCd"];
            continue;
        }

        if (oldArvHh != "" && rowData["dptHh"] != "") {
            if (ds_emp2.getRowStatusValue(i) == "3") {
                if (rowData["wrkStpCd"] != DsConstants.WRK_STP_CD_SHUTTLE
                    && rowData["dptDt"] != ""
                    && rowData["dptHh"] != ""
                    && oldArvDt != ""
                    && oldArvHh != ""
                    && (rowData["dptDt"] + rowData["dptHh"]) <= (oldArvDt + oldArvHh)) {
                    $c.gus.cfAlertMsg(i + "번째 데이타에서 시작일시가 " + j + "번째 종료일시보다  이후 이어야 합니다.");
                    return true;
                }
            }
        }
        else {
            continue;
        }

        if (rowData["arvIoMgntYn"] == 0) {
            oldArvDt = rowData["arvDt"];
            oldArvHh = rowData["arvHh"];
        } else if (rowData["dptIoMgntYn"] == 0) {
            oldArvDt = rowData["dptDt"];
            oldArvHh = rowData["dptHh"];
        } else {
            oldArvDt = "";
            oldArvHh = "";
        }
    }
    return false;
}

//-------------------------------------------------------------------------
// 그리드 시간 체크 함수
//-------------------------------------------------------------------------
scwin.hourCheck = async function () {
    return true;
}

scwin.hourNullCheck = async function () {
    for (i = 0; i < ds_emp2.getTotalRow(); i++) {
        if (ds_emp2.getRowStatusValue(i) == "3") {

            if (ds_emp2.getCellData(i, "arvHh") == "") {
                ds_emp2.setCellData(i, "arvDt", "");
            }
            if (ds_emp2.getCellData(i, "dptHh") == "") {
                ds_emp2.setCellData(i, "dptDt", "");
            }

            let chkVal = await dscommon.cf_gidHourNullCheck(ds_emp2.getCellData(i, "arvHh"))

            if (!chkVal) {
                ds_emp2.setRowPosition(i);
                // gr_emp2.ColSelect = "true"; // ???
                await $c.gus.cfAlertMsg(i + "번째 도착시간을 정확한 시간을 입력하세요");
                gr_emp2.setFocusedCell(ds_emp2.getRowPosition(), "arvHh");
                return false;
            }

        }
    }
    return true;
}

//-------------------------------------------------------------------------
// 출발일시 from ~ to 체크 함수
//-------------------------------------------------------------------------
scwin.f_DifferBetweenDate = function (sDateStr, eDateStr, dateFormat, row) {
    sDateStr = sDateStr.trim();
    eDateStr = eDateStr.trim();
    if (eDateStr == "00" || sDateStr == "00") {
        return true;
    }
    // 종료일자가 시작일자 이후인지 확인
    if (sDateStr >= eDateStr) {
        return false;
    }
    return true;
}


//-------------------------------------------------------------------------
// Popup 처리 : 그리드에서 입력된 코드정보 조회
//-------------------------------------------------------------------------
scwin.f_openCommPopUpGrid = async function (disGubun, row, pClose) {

    // 선언부
    var rtnList;  // 공통POP-UP -> 요청화면 
    var pCode = "";
    var pName = "";
    var colNm = new Array();

    let rowData = ds_emp2.getRowJSON(row);

    if (disGubun == "1") {
        colNm[0] = "cntrSizCd";
        colNm[1] = "cntrTypCd";
        colNm[2] = "fullEmptyClsCd";
        pCode = rowData["cntrNo"];
        pName = rowData["odrNo"];                               	//data;
        pWhere = rowData["cntrSeq"] + "," + rowData["odrNo"];
        //pClose = "T";
        pAllSearch = "F";

        udc_comCodeGrid.setSelectId('retrieveConteinerNo');
        await udc_comCodeGrid.cfCommonPopUpAsync(
            async (rtnList) => {
                //	$c.gus.cfSetGridReturnValue(rtnList, ds_emp2, row, "cntrNo", "", colNm);
                ds_emp2.setCellData(row + 1, "cntrNo", rowData["cntrNo"]);

                if (rtnList != null) {
                    if (rtnList[0] != "N/A") {

                        if (rowData["lineCd"] != rtnList[6]) {
                            $c.win.alert(
                                "오더LINE = "
                                + rowData["lineCd"]
                                + " // 컨테이너LINE = " + rtnList[6]
                                + " 컨테이너와 오더의 LINE이 불일치합니다."
                            );
                            ds_emp2.setCellData(row, "cntrNo", "");
                            return false;
                        }

                        ds_emp2.setCellData(row, "cntrNo", rtnList[0]);
                        ds_emp2.setCellData(row, "cntrSizCd", rtnList[2]);
                        ds_emp2.setCellData(row, "cntrTypCd", rtnList[3]);
                        ds_emp2.setCellData(row, "arrvlportDtm", rtnList[5]);
                        ds_emp2.setCellData(row, "socYn", rtnList[7]);
                        ds_emp2.setCellData(row + 1, "cntrNo", rtnList[0]);
                        ds_emp2.setCellData(row + 1, "cntrSizCd", rtnList[2]);
                        ds_emp2.setCellData(row + 1, "cntrTypCd", rtnList[3]);
                        ds_emp2.setCellData(row + 1, "arrvlportDtm", rtnList[5]);
                        ds_emp2.setCellData(row + 1, "socYn", rtnList[7]);
                    }
                }

            } // XML상의 SELECT ID	
            , pCode					// 화면에서의 ??? Code Element의	Value
            , pName					// 화면에서의 ??? Name Element의	Value
            , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
            , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
            , null					// Title순서	
            , null					// 보여주는 각 컬럼들의 폭	
            , null					// 컬럼중에서 숨기는	컬럼 지정	
            , pWhere					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
            , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
            , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
            , null					// 윈도우 위치 Y좌표	
            , null					// 윈도우 위치 X좌표
            , null					// 중복체크여부	("F")
            , pAllSearch					// 전체검색허용여부	("F")
            //,"컨테이너,컨테이너번호,,규격,F/E"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
        );
    }
    else {
        pCode = rowData["chassisNo"];
        //pName = rowData["chassisNo"];
        //pClose = "T";
        pAllSearch = "F";
        udc_comCodeGrid.setSelectId('retrieveChassisNo_tpro')
        await udc_comCodeGrid.cfCommonPopUpAsync(
            async (rtnList) => {
                $c.gus.cfSetGridReturnValue(rtnList, ds_emp2, row, "chassisEqCd", "chassisNo");

                if (rtnList != null)
                    ds_emp2.setCellData(row, "chassisEqCd", rtnList[4]);
                ds_emp2.setCellData(row + 1, "chassisNo", rowData["chassisNo"]);
                ds_emp2.setCellData(row + 1, "chassisEqCd", rowData["chassisEqCd"]);
            } // XML상의 SELECT ID
            , pCode                  // 화면에서의 ??? Code Element의  Value
            , pName                  // 화면에서의 ??? Name Element의  Value
            , pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부  (T:Close,F:Opened)
            , null                   // 검색 결과  컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
            , null                   // Title순서
            , null                   // 보여주는 각 컬럼들의 폭
            , null                   // 컬럼중에서 숨기는  컬럼 지정
            , 'C'                    // SQL절의 WHERE절에  원하는 조건을 선택함 MAX:8개까지 가능
            , null                   // POP-UP뛰을때 원도우의  사용자 정의 폭
            , null                   // POP-UP뛰을때 우도우의  사용자 정의 높이
            , null                   // 윈도우 위치 Y좌표
            , null                   // 윈도우 위치 X좌표
            , null                   // 중복체크여부 ("F")
            , 'F'                    // 전체검색허용여부 ("F")
            , null                   // POP-UP Window Title 검색어1,2   ("Win타이틀,첫번검색Nm,두번?검색Nm")
        );
    }

    //당사가 컨관리나 무브먼트를 제공하는 OFF-DOCK 선사(OP420)
    //2015.04.22
    var codeGrp = "OP420";
    // scwin.f_retrieveCodeList(codeGrp, rowData["lineCd"]);
    if (!$c.gus.cfIsNull(dma_codeInfo.get("col1"))												//당사가 컨관리나 무브먼트를 제공하는 OFF-DOCK 선사가 아니고
        && rowData["selfClsCd"] == DsConstants.SELF_CLS_CD_SELF_SALES) {		//자가영업이면
        // 출도착은 작업장 기준으로 처리함...
        // 입력된 컨테이너 번호로 SD404의 MGNT_CLS_YN = 1 인 컨테이너가 있으면 메세지 출력

        sbm_chkContainer.action = "/ncall.cm.zz.RetrieveComboCMD.do?sysCd=TransResultsEBC" +
            "&queryId=retrieveManagementedContainerCnt" +
            "&param1=" + rowData["cntrNo"];
        await scwin.submitExcute(sbm_chkContainer);

        if (dma_chkContainer.get("cd") != "0") {
            $c.win.alert("컨테이너 "
                + rowData["cntrNo"] + "는 관리구분이 살아있는 컨테이너가 "
                + dma_chkContainer.get("cd")
                + "개 있습니다.\n 관리구분을 수정하시고 작업을 진행하십시오.");
            ds_emp2.setCellData(row, "cntrNo", "");
            ds_emp2.setCellData(row + 1, "cntrNo", "");
            return false;
        }
    }
}


