// 미지정(컨테이너, 차량)의 컨테이너 SEQ 세팅 
scwin.f_cntrSeqSearch = async function () {

    let empPos = ds_emp.getRowPosition();
    let empPos2 = ds_emp2.getRowPosition();
    let rowData1 = ds_emp.getRowJSON(empPos);
    let rowData2 = ds_emp2.getRowJSON(empPos2);

    if (rowData1["cntrSeq"] == 0
        && !$c.gus.cfIsNull(rowData1["cntrNo"])
        && !$c.gus.cfIsNull(rowData2["cntrNo"])
        && (["B", "C"].includes(rowData1["reqClsCd"]))) {
        ds_CntrNoSeqInfo.action = "/ncall.tn.os.odrrslts.odrrslts.RetrieveContainerSeqInformationCMD.do"
            + "?cntrNo=" + rowData2["cntrNo"]
            + "&odrNo=" + rowData2["odrNo"]
            + "&alloccarNo=" + rowData1["alloccarNo"]
            + "&alloccarSeq=" + rowData1["alloccarSeq"]
            + "&reqClsCd=" + rowData1["reqClsCd"]
            ;
        scwin.submitExcute(sbm_CntrNoSeqInfo);
    }
}


