    ds_emp2.setCellData(empPos2, "cntrNo", dataSet["cntrNo"]);
    ds_emp2.setCellData(empPos2, "cntrSeq", dataSet["cntrSeq"]);
    ds_emp2.setCellData(empPos2, "wrkPathSeq", dataSet["wrkPathSeq"]);
    ds_emp2.setCellData(empPos2, "wrkStpSeq", dataSet["wrkStpSeq"]);
    ds_emp2.setCellData(empPos2, "arrvlportDtm", dataSet["arrvlportDtm"]);
};


// for="tr_retrieve2" event="OnSuccess()"
scwin.sbm_retrieve2_submitdone = function (e) {
    /* 경기지사 오더 배차장 진행 시 
       배차할때 샤시번호 null 등록 후 실제 배차 진행 할때 샤시번호 입력 함
       => 출도착등록에서 DOOR회수 부분의 샤시번호가 NULL로 세팅 됨
       => 샤시번호가 NULL인 경우 이전 샤시번호 세팅하도록 함. 
    */
    if (ds_emp2.getTotalRow() > 0) {
        for (var i = 0; i < ds_emp2.getTotalRow(); i++) {
            if ($c.gus.cfIsNull(ds_emp2.getCellData(i + 1, "chassisNo"))) {
                ds_emp2.setCellData(i + 1, "chassisNo", ds_emp2.getCellData(i, "chassisNo"));
                ds_emp2.setCellData(i + 1, "chassisEqCd", ds_emp2.getCellData(i, "chassisEqCd"));
            }
        }
    }
    let rowCnt = ds_emp2.getTotalRow();
    totalRows.setValue(rowCnt);
};


// Grid Click시 : 수정여부에 따라 Editable
// FOR=ds_emp2 EVENT=OnRowPosChanged(row)
scwin.ds_emp2_onrowpositionchange = function (info) {

    let colid = gr_emp2.getColumnID(info.newRowIndex)

    let row = info.newRowIndex;

    var v_msg = "";
    if (["dptDt", "dptHh", "arvDt", "arvHh"].includes(colid)) {
        //셔틀단계는 날짜체크를 하지 않는다
        let rowPos = ds_emp.getRowPosition()
        if (ds_emp.getCellData(rowPos, "wrkStpCd") != DsConstants.WRK_STP_CD_SHUTTLE) {
            for (var i = 0; i < ds_emp2.getTotalRow(); i++) {
                if (i < row) {
                    let rowData = ds_emp2.getRowJSON(i);
                    if ((rowData["dptIoMgntYn"] == 0 && rowData["dptHh"] == "")
                        || (rowData["arvIoMgntYn"] == 0 && rowData["arvHh"] == "")) {
                        $c.data.undoRow(ds_emp2, "Y"); // ds_emp2.Undo(row);
                        gr_emp2.setReadOnly("grid", true);
                        return;
                    }
                }
            }
        }
        gr_emp2.setReadOnly("grid", false);
    }

    switch (colid) {
        case "cntrNo":

            let rowData = ds_emp2.getRowJSON(row)
            let rowPos = ds_emp2.getRowPosition()
            let rowPosData = ds_emp2.getRowJSON(rowPos)

            if (rowData["selfClsCd"] == DsConstants.SELF_CLS_CD_MCOM_TRANS) {
                //당사운송인경우
                if (rowPosData["dptIoMgntYn"] == 1 || rowPosData["arvIoMgntYn"] == 1) {
                    ds_emp2.setCellData(row, colid, ds_emp2.getCellData(row, colid));
                    gr_emp2.setCellReadOnly(row, colid, true);
                    return;
                } else {
                    // gr_emp2.ColumnProp(colid, "Edit") = 'Upper';
                    // gr_emp2.ColumnProp(colid, 'EditStyle') = 'Popup';
                    gr_emp2.setReadOnly("cell", info.newRowIndex, colid, false)
                }
            } else if (rowData["selfClsCd"] == DsConstants.SELF_CLS_CD_SELF_SALES) {
                //자가영업인경우
                if (rowPosData["dptIoMgntYn"] == 1 && rowPosData["arvIoMgntYn"] == 1) {
                    ds_emp2.setCellData(row, colid, ds_emp2.getCellData(row, colid));
                    gr_emp2.setCellReadOnly(row, colid, true);
                    return;
                } else {
                    // gr_emp2.ColumnProp(colid, "Edit") = 'Upper';
                    // gr_emp2.ColumnProp(colid, 'EditStyle') = 'Popup';
                    gr_emp2.setReadOnly("cell", info.newRowIndex, colid, false)
                }
            } else {
                if (rowPosData["dptIoMgntYn"] == 1 && rowPosData["arvIoMgntYn"] == 1) {
                    ds_emp2.setCellData(row, colid, ds_emp2.getCellData(row, colid));
                    gr_emp2.setCellReadOnly(row, colid, true);
                    return;
                } else {
                    // gr_emp2.ColumnProp(colid, "Edit") = 'Upper';
                    // gr_emp2.ColumnProp(colid, 'EditStyle') = 'Popup';
                    gr_emp2.setReadOnly("cell", info.newRowIndex, colid, false)
                }
            }
            break;
        case "dptDt":
            if (ds_emp2.getCellData(row, "cntrNo") == "") {
                ds_emp2.setCellData(row, colid, ds_emp2.getCellData(row, colid));
                gr_emp2.setCellReadOnly(row, colid, true);
                return;
            }

            if (ds_emp2.getCellData(ds_emp2.getRowPosition(), "dptIoMgntYn") == 1) {
                ds_emp2.setCellData(row, colid, ds_emp2.getCellData(row, colid));
