                } else {
                    gr_emp2.setCellReadOnly(row, colid, false);
                }
            }

            if (ds_emp.getCellData(ds_emp.getRowPosition(), "dptWrkPlCd") == "6C09"
                || ds_emp.getCellData(ds_emp.getRowPosition(), "dptWrkPlCd") == "6C01") {
                gr_emp2.setCellReadOnly(row, "dptHh", true);
                gr_emp2.setCellReadOnly(row, "dptDt", true);
            }

            // to-do
            // gr_emp2.UrlImageProp("PopupBotton", "Url") = "/common/images/Content_icon_calender.gif";
            break;
        case "dptHh":
            if (ds_emp2.getCellData(row, "cntrNo") == "") {
                ds_emp2.setCellData(row, colid, ds_emp2.getCellData(row, colid));
                gr_emp2.setCellReadOnly(row, colid, true);
                return;
            }
            if (ds_emp2.getCellData(row, "dptDt") == "") {
                ds_emp2.setCellData(row, colid, ds_emp2.getCellData(row, colid));
