                return;
            }
            if (ds_emp2.getCellData(ds_emp2.getRowPosition(), "dptIoMgntYn") == 1
                || ds_emp2.getCellData(ds_emp2.getRowPosition(), "cntrNo") == "") {
                ds_emp2.setCellData(row, colid, ds_emp2.getCellData(row, colid));
