};


// FOR=gr_emp2	EVENT=OnColumnPosChanged(row,colid)
scwin.gr_emp2_oncellindexchange = function (rowIndex, columnIndex, oldRow, oldColumnIndex) {
    let colid = gr_emp2.getColumnID(columnIndex);
    let v_msg = "";
    let row = rowIndex;

    if (["dptDt", "dptHh", "arvDt", "arvHh"].includes(colid)) {
        //셔틀단계는 날짜체크를 하지 않는다
        if (ds_emp.getCellData(ds_emp.getRowPosition(), "wrkStpCd") != DsConstants.WRK_STP_CD_SHUTTLE) {
            for (var i = 0; i < ds_emp2.getTotalRow(); i++) {
                if (i < rowIndex) {
                    if ((ds_emp2.getCellData(i, "dptIoMgntYn") == 0 && ds_emp2.getCellData(i, "dptHh").trim() == "")
                        || (ds_emp2.getCellData(i, "arvIoMgntYn") == 0 && ds_emp2.getCellData(i, "arvHh").trim() == "")) {
                        $c.data.undoRow(ds_emp2, "Y"); // ds_emp2.Undo(row);
                        // gr_emp2.setReadOnly("grid", true);

                        gr_emp2.setReadOnly("cell", rowIndex, "cntrNo", true); //Editable = false;
                        gr_emp2.setReadOnly("cell", rowIndex, "sealNo", true); //Editable = false;
                        gr_emp2.setReadOnly("cell", rowIndex, "dptDt", true); //Editable = false;
                        gr_emp2.setReadOnly("cell", rowIndex, "dptHh", true); //Editable = false;
                        gr_emp2.setReadOnly("cell", rowIndex, "arvDt", true); //Editable = false;
                        gr_emp2.setReadOnly("cell", rowIndex, "arvHh", true); //Editable = false;
                        gr_emp2.setReadOnly("cell", rowIndex, "chassisNo", true); //Editable = false;'

                        $c.gus.cfAlertMsg("이전단계의 실적이 발생하지 않은 상태에서 이후단계의 실적이 발생하면 안됩니다");
                        return;
                    }
                }
            }
        }
        // gr_emp2.setReadOnly("grid", false);

        gr_emp2.setReadOnly("cell", rowIndex, "cntrNo", false); //Editable = false;
        gr_emp2.setReadOnly("cell", rowIndex, "sealNo", false); //Editable = false;
        gr_emp2.setReadOnly("cell", rowIndex, "dptDt", false); //Editable = false;
        gr_emp2.setReadOnly("cell", rowIndex, "dptHh", false); //Editable = false;
        gr_emp2.setReadOnly("cell", rowIndex, "arvDt", false); //Editable = false;
        gr_emp2.setReadOnly("cell", rowIndex, "arvHh", false); //Editable = false;
        gr_emp2.setReadOnly("cell", rowIndex, "chassisNo", false); //Editable = false;'
    }

    switch (colid) {
        case "cntrNo":
            if (ds_emp2.getCellData(rowIndex, "selfClsCd") == DsConstants.SELF_CLS_CD_MCOM_TRANS) {
                //당사운송인경우
                if (ds_emp2.getCellData(ds_emp2.getRowPosition(), "dptIoMgntYn") == 1 || ds_emp2.getCellData(ds_emp2.getRowPosition(), "arvIoMgntYn") == 1) {
                    ds_emp2.setCellData(rowIndex, colid, ds_emp2.getCellData(rowIndex, colid));
                    gr_emp2.setCellReadOnly(rowIndex, colid, true);
                    $c.gus.cfAlertMsg("당사운송인 경우에는 출도착지 모두 입출고관리대상이 아니어야 합니다");
                    return;
