                    ds_emp2.setCellData(rowIndex, colid, ds_emp2.getCellData(rowIndex, colid));
                    gr_emp2.setCellReadOnly(rowIndex, colid, true);
                    $c.gus.cfAlertMsg("자가영업인 경우에는 출도착지중 하나는 입출고관리대상이 아니어야 합니다");
