            }

            if (ds_emp.getCellData(ds_emp.getRowPosition(), "arvWrkPlCd") == "6C09"
                || ds_emp.getCellData(ds_emp.getRowPosition(), "arvWrkPlCd") == "6C01") {
                gr_emp2.setCellReadOnly(rowIndex, "arvHh", true);
                gr_emp2.setCellReadOnly(rowIndex, "arvDt", true);
            }

            break;
        case "chassisNo":
            // to-do
            // gr_emp2.UrlImageProp("PopupBotton", "Url") = "/common/images/search.gif";
            break;
        default:
            break;
    }
    return;
};

