                }


                // gr_emp2.UrlImageProp("PopupBotton", "Url") = "/common/images/search.gif";
                if (ds_emp2.getCellData(row, colid) != "" && ds_emp2.getCellData(row, colid) != scwin.olddata) {
                    //f_openCommPopUpGrid('1', row, 'T');
                    ds_emp2.setCellData(row + 1, "cntrNo", ds_emp2.getCellData(row, "cntrNo"));
                } else if (ds_emp2.getCellData(row, colid) == "") {
                    ds_emp2.setCellData(row, "cntrNo", "");
                }

                for (var i = 1; i <= ds_emp2.getRowCount() - 1; i++) {
                    for (var j = i + 1; j <= ds_emp2.getRowCount(); j++) {
                        if (ds_emp2.getCellData(j, "cntrNo") != "" && ds_emp2.getCellData(i, "cntrNo") != "") {
                            if (ds_emp2.getCellData(i, "wrkPathSeq") == ds_emp2.getCellData(j, "wrkPathSeq")
                                && ds_emp2.getCellData(i, "odrNo") == ds_emp2.getCellData(j, "odrNo")
                                && ds_emp2.getCellData(j, "cntrNo") != ds_emp2.getCellData(i, "cntrNo")) {
                                $c.gus.cfAlertMsg(Number(j) + 1 + "번째 줄에 같은 작업경로에 다른 컨테이너번호가 있습니다.");
                                ds_emp2.setCellData(j, "cntrNo", "");
                                return;
                            }
                            if (ds_emp2.getCellData(i, "wrkPathSeq") != ds_emp2.getCellData(j, "wrkPathSeq")
                                && ds_emp2.getCellData(i, "odrNo") == ds_emp2.getCellData(j, "odrNo")
                                && ds_emp2.getCellData(j, "cntrNo") == ds_emp2.getCellData(i, "cntrNo")) {
                                $c.gus.cfAlertMsg(Number(j) + 1 + "번째 줄에 다른 작업경로에 같은 컨테이너번호가 있습니다.");
                                ds_emp2.setCellData(j, "cntrNo", "");
                                return;
                            }

                            // 복화종류=컴바인 같은 작업경로순번인데 같은 컨테이너번호일 경우.
                            if (ds_emp2.getCellData(i, "wrkPathSeq") != ds_emp2.getCellData(j, "wrkPathSeq")
                                && ds_emp2.getCellData(i, "cmpstcrgKndCd") == "CB"
                                && ds_emp2.getCellData(j, "cmpstcrgKndCd") == "CB"
                                && ds_emp2.getCellData(j, "cntrNo") == ds_emp2.getCellData(i, "cntrNo")) {
                                $c.gus.cfAlertMsg(Number(j) + 1 + "번째 줄의 작업지시는 컴바인이므로 컨테이너번호가 달라야 합니다.");
                                ds_emp2.setCellData(j, "cntrNo", "");
                                ds_emp2.setCellData(j, "dptHh", ds_emp2.getCellData(i, "dptHh"));
                                ds_emp2.setCellData(j, "arvHh", ds_emp2.getCellData(i, "arvHh"));
                                return;
                            }
                        }
                    }
                }

                if (ds_emp2.getCellData(row, "cntrNo") != "") {
                    let chkVal = dscommon.cf_CheckCntrNo(ds_emp2.getCellData(row, "cntrNo"))
                    if (!chkVal) {
                        let confirm = await $c.win.confirm(Number(row + 1) + "번째 컨테이너 번호는 유효하지 않은 컨테이너입니다. 계속진행하시겠습니까?");
                        if (!confirm) {
                            return;
                        }
                    }
                }
                break;
            case "chassisNo":
                // gr_emp2.UrlImageProp("PopupBotton", "Url") = "/common/images/search.gif";
                if (ds_emp2.getCellData(row, colid) != "" && ds_emp2.getCellData(row, colid) != scwin.olddata) {
                    scwin.f_openCommPopUpGrid('2', row, 'T');
                }
                else if (ds_emp2.getCellData(row, colid) == "") {
                    ds_emp2.setCellData(row, "chassisNo", "");
                }
                break;
            case "sealNo":
                ds_emp2.setCellData(row + 1, "sealNo", ds_emp2.getCellData(row, "sealNo"));
                break;
            default:
                break;
        }
    }
};

// 그리드 팝업
// for=gr_emp2 event=OnPopup(row,colid,data)
scwin.gr_emp2_onpopup = function (rowIndex, colId, nowValue) {

    switch (colId) {
        case "cntrNo":
            scwin.f_openCommPopUpGrid('1', rowIndex, 'F');
            break;
        case "chassisNo":
            scwin.f_openCommPopUpGrid('2', rowIndex, 'F');
            break;
    }
}

// for=ed_cntrNo event=OnKillFocus()
scwin.ed_cntrNo_onblur = function (e) {
    if (!$c.gus.cfIsNull(ed_cntrNo.getValue())) scwin.f_openPopUpOdrNo();
};

// for=ds_joblevel event=OnLoadCompleted(rowCnt)
scwin.sbm_joblevel_submitdone = function (e) {

    //전체조건 추가
    ds_joblevel.sort("lobranNm", 0) // 이름순으로 정렬.
    let sLoUpperLobranCd = scwin.sLobranCd;
    if (co_lc_logisticsBranch.getValue() > 0) {
        co_lc_logisticsBranch.setValue(sLoUpperLobranCd);
    } else {
        co_lc_logisticsBranch.setValue(0);
    }
};

/**
 * @method 
 * @name submitdone 
 * @description submit 정상
 */
scwin.submitdone = async function (e) {

    let submitObj = $p.getComponentById(e.id);

    switch (submitObj) {
        case sbm_retrieve:
            await scwin.sbm_retrieve_submitdone(e);
            break;

        case sbm_joblevel:
            await scwin.sbm_joblevel_submitdone(e);
            break;

        case sbm_batch:

            break;

        case sbm_saveEmp:
            scwin.sbm_saveEmp_submitdone(e);
            break;

        case sbm_retrieve2:
            scwin.sbm_retrieve2_submitdone(e);
            break;

        case sbm_CntrNoSeqInfo:
            scwin.sbm_CntrNoSeqInfo_submitdone(e);
            break;

        default:
            break;
    }
};

/**
 * @method 
 * @name submitExcute 
 * @description submit 처리
 */
scwin.submitExcute = async function (sbmObj) {

    const e = await $c.sbm.execute(sbmObj);

    if (e.responseJSON.resultDataSet[0].Msg == 'SUCC') {
        if (e.responseJSON.resultDataSet[0].Code == -1) return;
        await scwin.submitdone(e);
    };
};

scwin.socYn_formatter = function (value) {
    if (value == 0) {
        return "N";
    } else {
        return "Y"
    }
}

